syntaxes.code:
v_name type := value;
v_name type DEFAULT value;
v_name CONSTANT type := value;
v_name type NOT NULL := value;

TYPE t_rec IS RECORD (
  f1 type1, f2 type2
);
v_rec t_rec;

WHILE condition LOOP
  ...
END LOOP;

LOOP
  ...
  EXIT WHEN condition;
END LOOP;

FOR i IN [REVERSE] lower..upper LOOP
  ...
END LOOP;

OPEN cur_name;
FETCH cur_name INTO v1, v2;
CLOSE cur_name;

OPEN cur;
LOOP
  FETCH cur INTO vars;
  EXIT WHEN cur%NOTFOUND;
  ...
END LOOP;
CLOSE cur;

OPEN cur;
FETCH cur INTO vars;
WHILE cur%FOUND LOOP
  ...
  FETCH cur INTO vars;
END LOOP;
CLOSE cur;

rec cur%ROWTYPE;
FETCH cur INTO rec;
-- rec.col_name

FOR rec IN cur_name LOOP
  -- auto OPEN, FETCH, %NOTFOUND, CLOSE
  DBMS_OUTPUT.PUT_LINE(rec.col);
END LOOP;

FOR rec IN (SELECT col FROM table) LOOP
  DBMS_OUTPUT.PUT_LINE(rec.col);
END LOOP;

DECLARE
  v_nb NUMBER;
BEGIN
  proc_name(100, 'IT', v_nb);
END;

-- In PL/SQL block:
IF func_name(124) THEN ... END IF;

-- In SQL:
SELECT func_name(col) FROM table;

DECLARE
  PROCEDURE local_proc(a IN NUMBER, b OUT NUMBER) IS
  BEGIN
    b := a * 2;
  END;
BEGIN
  local_proc(5, result);
END;

DECLARE
  FUNCTION local_func(x NUMBER) RETURN NUMBER IS
  BEGIN
    RETURN x * x;
  END;
BEGIN
  result := local_func(5);
END;

CREATE TRIGGER trig_row
  BEFORE INSERT OR UPDATE OR DELETE
  ON departments
  FOR EACH ROW
BEGIN
  IF INSERTING THEN
    DBMS_OUTPUT.PUT_LINE('Insert');
  END IF;
END;

ALTER TRIGGER trig_name ENABLE;
ALTER TRIGGER trig_name DISABLE;
DROP TRIGGER trig_name;

DECLARE
  e_myerr EXCEPTION;
  PRAGMA EXCEPTION_INIT(e_myerr, -20001);
BEGIN
  IF cond THEN
    RAISE e_myerr;
  END IF;
EXCEPTION
  WHEN e_myerr THEN ...
END;

RAISE_APPLICATION_ERROR(
  error_number,  -- -20000 to -20999
  message        -- max 2048 bytes
);

EXCEPTION
  WHEN OTHERS THEN
    DBMS_OUTPUT.PUT_LINE('Code: '||SQLCODE);
    DBMS_OUTPUT.PUT_LINE('Msg:  '||SQLERRM);
    ROLLBACK;
END;
